16	// Helper to create a minimal valid Gallops structure
17	// Sets next_heat_seed to "AC" so that manually-created "AB" heat doesn't conflict
18	fn make_valid_gallops() -> jjrg_Gallops {
19	    jjrg_Gallops {
20	        schema_version: Some(4),
21	        next_heat_seed: "AC".to_string(),
22	        heat_order: vec![],
23	        heats: BTreeMap::new(),
24	    }
25	}
26	
27	// Helper to create a valid Tack
28	fn make_valid_tack(state: jjrg_PaceState, silks: &str, direction: Option<String>) -> jjrg_Tack {
29	    jjrg_Tack {
30	        ts: "260101-1200".to_string(),
31	        state,
32	        text: "Test tack text".to_string(),
33	        silks: silks.to_string(),
34	        basis: JJRG_UNKNOWN_BASIS.to_string(),
35	        direction,
36	    }
37	}
38	
39	// Helper to create a valid Heat with multiple paces
40	fn make_heat_with_paces(heat_id: &str, silks: &str, pace_states: Vec<jjrg_PaceState>) -> (String, jjrg_Heat) {
41	    let heat_key = format!("₣{}", heat_id);
42	    let mut paces = BTreeMap::new();
43	    let mut order = Vec::new();
44	
45	    for (idx, state) in pace_states.iter().enumerate() {
46	        let pace_key = format!("₢{}AA{}", heat_id, char::from(b'A' + idx as u8));
47	        let pace_silks = format!("pace-{}", idx);
48	        let pace = jjrg_Pace {
49	            tacks: vec![make_valid_tack(state.clone(), &pace_silks, None)],
50	        };
51	        paces.insert(pace_key.clone(), pace);
52	        order.push(pace_key);
53	    }
54	
55	    // Calculate next seed
56	    let next_char = char::from(b'A' + pace_states.len() as u8);
57	    let next_pace_seed = format!("AA{}", next_char);
58	
59	    let heat = jjrg_Heat {
60	        silks: silks.to_string(),
61	        creation_time: "260101".to_string(),
62	        status: jjrg_HeatStatus::Racing,
63	        order,
64	        next_pace_seed,
65	
66	        paddock_file: format!(".claude/jjm/jjp_{}.md", heat_id),
67	        paces,
68	    };
69	    (heat_key, heat)
70	}
