    let old_order = heat.order.clone();
    gallops.heats.insert(hk, heat);

    let args = jjrg_RailArgs {
        firemark: "AB".to_string(),
        order: vec![],
        move_coronet: Some("₢ABAAC".to_string()),
        before: None,
        after: None,
        first: false,
        last: true,
    };

