        "₣AC".to_string(),
        Heat {
            silks: "mixed-state-heat".to_string(),
            creation_time: "260101".to_string(),
            status: HeatStatus::Racing,
            order: vec![
                "₢ACAAA".to_string(),
                "₢ACAAB".to_string(),
                "₢ACAAC".to_string(),
                "₢ACAAD".to_string(),
            ],
            next_pace_seed: "AAE".to_string(),

            paddock_file: ".claude/jjm/jjp_AC.md".to_string(),
            paces,
        },
    );

    Gallops {
